/* ============================================================
   DIBUJOS EN BASE64
   ¿Por qué van inline y no como archivos sueltos?
   El efecto "boiling" pre-renderiza los trazos en un <canvas>.
   Si abres index.html directamente (file://), el navegador
   bloquea por seguridad el uso en canvas de imágenes cargadas
   como archivo local ("canvas tainted"). Con data-URLs no hay
   restricción y funciona igual en local y en producción.
   (Los PNG originales están en /assets/img por si los necesitas.)
   ============================================================ */
const IMG_OJOABIERTO = "data:image/png;base64,";
const IMG_OJOCERRADO = "data:image/png;base64,";
const IMG_VINILO = "data:image/png;base64,";
const IMG_BRAZO = "data:image/png;base64,";

const IMGS = {
  ojoAbierto: IMG_OJOABIERTO,
  ojoCerrado: IMG_OJOCERRADO,
  vinilo:     IMG_VINILO,
  brazo:      IMG_BRAZO,
};
